import java.util.stream.*;
public class InfiniteStream {
    public static void main(String[] args) {
        Stream.iterate(1, n -> n * 2)
            .limit(6)
            .forEach(n -> System.out.print(n + " "));
        System.out.println();
        int sum = IntStream.range(1, 6).sum();
        System.out.println(sum);
    }
}
